/// <summary>
/// Extension of the <c>SalesAgreementHeaderHistory</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(SalesAgreementHeaderHistory))]
public final class SalesAgreementHeaderHistoryETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>initFromSalesAgreementHeader</c> method.
/// </summary>
/// <param name="_salesAgreementHeader">SalesAgreementHeader.</param>
public void initFromSalesAgreementHeader(SalesAgreementHeader _salesAgreementHeader)
{
    next initFromSalesAgreementHeader(_salesAgreementHeader);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        this.ETGSPAINCreationDate                        = DateTimeUtil::date(_salesAgreementHeader.CreatedDateTime);
        this.ETGSPAINPurchExecutionDueDate               = _salesAgreementHeader.ETGSPAINPurchExecutionDueDate;
        this.ETGSPAINPurchExecutionFromDate              = _salesAgreementHeader.ETGSPAINPurchExecutionFromDate;
        this.ETGSPAINSalesVendGroup                      = _salesAgreementHeader.custTable().CustGroup;
        this.ETGSPAINPurchPlateDaysNumber                = _salesAgreementHeader.ETGSPAINPurchPlateDaysNumber;
        this.ETGSPAINDefaultAgreementLineEffectiveDate   = _salesAgreementHeader.DefaultAgreementLineEffectiveDate;

        AgreementLine               agreementLine;
        ETGSPAINPurchUnloadPortTable     ETGSPAINPurchUnloadPortTable;
        ETGSPAINPurchLoadPortTable       ETGSPAINPurchLoadPortTable;

        select firstonly agreementLine
        order by ETGSPAINPurchLoadPortId desc
        where agreementLine.Agreement                       == _salesAgreementHeader.RecId
            outer join ETGSPAINPurchLoadPortTable
                where ETGSPAINPurchLoadPortTable.LoadPortId      == agreementLine.ETGSPAINPurchLoadPortId;

        this.ETGSPAINLoadCity                            = ETGSPAINPurchLoadPortTable.AdressCity;

        select firstonly agreementLine
        order by ETGSPAINPurchUnloadPortId desc
        where agreementLine.Agreement                       == _salesAgreementHeader.RecId
            outer join ETGSPAINPurchUnloadPortTable
                where ETGSPAINPurchUnloadPortTable.UnloadPortId  == agreementLine.ETGSPAINPurchUnloadPortId;

        this.ETGSPAINUnloadCity                          = ETGSPAINPurchUnloadPortTable.AdressCity;
    }
}
